function ticker(e){var t={USD:"$",CNY:"\xa5",JPY:"\xa5",EUR:"\u20ac"};$.ajax({type:"GET",url:"https://min-api.cryptocompare.com/data/price?fsym=BCH&tsyms="+e,contentType:"application/json; charset=utf-8",timeout:6e3,error:function(){$("#ticker_value").html().includes("BCH")||$("#ticker_value").html("N/A")},success:function(e){var c=[];$.each(e,function(e,i){var r=t[e];void 0!==r&&c.push("BCH/"+e+"&nbsp;"+r+i)}),c.length>0?$("#ticker_value").html(c.join(" &bull; ")):$("#ticker_value").html().includes("BCH")||$("#ticker_value").html("N/A")}}).done(function(){setTimeout(function(){ticker(ticker_currencies)},update_interval)}).fail(function(){setTimeout(function(){ticker(ticker_currencies)},update_interval)})}var ticker_currencies="USD,EUR,JPY,CNY",update_interval=3e4;ticker(ticker_currencies);